   783→      if (parentSessionId) envParts.push(`GOSSAMER_SPAWN_PARENT_SESSION='${parentSessionId.replace(/'/g, "")}'`);
   784→      const envPrefix = envParts.length ? envParts.join(" ") + " " : "";
   785→      // Use AppleScript to open a new Terminal window running claude interactively
   786→      const script = [
   787→        `tell application "Terminal"`,
   788→        `  activate`,
   789→        `  do script "cd '${safeCwd}' && ${envPrefix}claude '${safePrompt}'"`,
   790→        `end tell`,
   791→      ].join("\n");
   792→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   793→      // Mark selected open items as in_progress
   794→      if (openItemIds?.length) {
   795→        await db.openItem.updateMany({
   796→          where: { id: { in: openItemIds } },
   797→          data: { status: "in_progress" },
   798→        });
