  1002→  // ── WebSocket change detection — poll every 2s across all known repo dbs ──
  1003→
  1004→  // Per-db watermarks keyed by dbPath
  1005→  const wsWatermarks = new Map<string, { logEvent: number | null; checkpoint: number | null; shadow: number | null }>();
  1006→
  1007→  const poller = setInterval(async () => {
  1008→    const repos = readConfig().repos;
  1009→    const nameByDbPath = new Map(repos.map((r) => [r.dbPath, r.name]));
  1010→    // Always include the primary db even if it isn't in config yet
  1011→    const dbPaths = [...new Set([dbPath, ...repos.map((r) => r.dbPath)])];
  1012→    let changed = false;
  1013→    await Promise.all(dbPaths.map(async (p) => {
  1014→      try {
  1015→        const repoDb = await getDb(p);
  1016→        const [latestLogEvent, latestCheckpoint, latestShadow] = await Promise.all([
  1017→          repoDb.logEvent.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
  1018→          repoDb.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
  1019→          repoDb.shadowSession.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
  1020→        ]);
  1021→        const cur = {
  1022→          logEvent:   latestLogEvent?.id   ?? null,
  1023→          checkpoint: latestCheckpoint?.id ?? null,
  1024→          shadow:     latestShadow?.id     ?? null,
  1025→        };
  1026→        const prev = wsWatermarks.get(p);
  1027→        if (!prev || prev.logEvent !== cur.logEvent || prev.checkpoint !== cur.checkpoint || prev.shadow !== cur.shadow) {
  1028→          wsWatermarks.set(p, cur);
  1029→          changed = true;
  1030→          const label = nameByDbPath.get(p) ?? p;
  1031→          process.stderr.write(`change poller [${label}]: change detected — broadcasting\n`);
  1032→        }
  1033→      } catch { /* non-fatal — db may not exist yet */ }
  1034→    }));
  1035→    if (changed) broadcast();
  1036→  }, 2000);
